import React, { useState, useEffect } from 'react';
import { getSalesAnalytics } from '../../services/dataService';
import { formatCurrency, formatDate } from '../../utils/helpers';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Pie, Bar, Doughnut } from 'react-chartjs-2';
import { FiTrendingUp, FiHome, FiUser, FiDollarSign, FiMapPin, FiCheckCircle, FiClock, FiBox } from 'react-icons/fi';
import './AdminAnalytics.css';

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const AdminAnalytics = () => {
  const [analytics, setAnalytics] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getSalesAnalytics();
        setAnalytics(res.data.data);
      } catch (err) { 
        console.error(err); 
      }
      finally { 
        setLoading(false); 
      }
    };
    fetch();
  }, []);

  if (loading) return <LoadingSpinner />;

  const metrics = analytics?.metrics || {};
  const soldProperties = analytics?.soldProperties || [];
  const availableProperties = analytics?.availableProperties || [];
  const reservedProperties = analytics?.reservedProperties || [];

  // Chart Data
  const statusData = {
    labels: ['Sold', 'Reserved', 'Available'],
    datasets: [{
      data: [metrics.soldProperties || 0, metrics.reservedProperties || 0, metrics.availableProperties || 0],
      backgroundColor: ['#10b981', '#f59e0b', '#3b82f6'],
      borderColor: ['#047857', '#d97706', '#1e40af'],
      borderWidth: 2
    }]
  };

  const typeData = {
    labels: analytics?.propertyByType?.map(t => t._id) || [],
    datasets: [{
      label: 'Total Properties',
      data: analytics?.propertyByType?.map(t => t.count) || [],
      backgroundColor: '#3b82f6',
      borderColor: '#1e40af',
      borderWidth: 2
    }, {
      label: 'Sold Properties',
      data: analytics?.propertyByType?.map(t => t.sold) || [],
      backgroundColor: '#10b981',
      borderColor: '#047857',
      borderWidth: 2
    }]
  };

  const salesData = {
    labels: analytics?.salesByMonth?.map(m => m._id) || [],
    datasets: [{
      label: 'Monthly Sales',
      data: analytics?.salesByMonth?.map(m => m.count) || [],
      backgroundColor: 'rgba(59, 130, 246, 0.5)',
      borderColor: '#3b82f6',
      borderWidth: 2,
      fill: true
    }]
  };

  const valueData = {
    labels: ['Sold Value', 'Remaining Value'],
    datasets: [{
      data: [metrics.soldValue || 0, metrics.remainingValue || 0],
      backgroundColor: ['#06b6d4', '#ec4899'],
      borderColor: ['#0891b2', '#be185d'],
      borderWidth: 2
    }]
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        labels: {
          font: { size: 12, weight: '600' },
          padding: 20,
          boxPadding: 10
        }
      },
      tooltip: {
        backgroundColor: 'rgba(0, 0, 0, 0.8)',
        padding: 12,
        titleFont: { size: 13 },
        bodyFont: { size: 12 }
      }
    }
  };

  const getPropertyTypeColor = (type) => {
    const colors = {
      apartment: '#3b82f6',
      house: '#10b981',
      villa: '#f59e0b',
      commercial: '#8b5cf6',
      land: '#ec4899',
      condo: '#06b6d4'
    };
    return colors[type] || '#6b7280';
  };

  const getPropertyStatusBadge = (status) => {
    const config = {
      sold: { bg: '#d1fae5', text: '#065f46', label: 'Sold' },
      available: { bg: '#dbeafe', text: '#1e40af', label: 'Available' },
      reserved: { bg: '#fef3c7', text: '#92400e', label: 'Reserved' }
    };
    return config[status] || config.available;
  };

  return (
    <div className="sales-analytics-container">
      <div className="analytics-header">
        <div className="header-content">
          <h1><FiTrendingUp /> Sales Analytics</h1>
          <p>Comprehensive property sales and inventory analysis</p>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="kpi-grid">
        <div className="kpi-card primary">
          <div className="kpi-icon"><FiHome /></div>
          <div className="kpi-content">
            <div className="kpi-value">{metrics.totalProperties || 0}</div>
            <div className="kpi-label">Total Properties</div>
          </div>
        </div>

        <div className="kpi-card success">
          <div className="kpi-icon"><FiCheckCircle /></div>
          <div className="kpi-content">
            <div className="kpi-value">{metrics.soldProperties || 0}</div>
            <div className="kpi-label">Sold Properties</div>
          </div>
        </div>

        <div className="kpi-card warning">
          <div className="kpi-icon"><FiClock /></div>
          <div className="kpi-content">
            <div className="kpi-value">{metrics.reservedProperties || 0}</div>
            <div className="kpi-label">Reserved Properties</div>
          </div>
        </div>

        <div className="kpi-card info">
          <div className="kpi-icon"><FiBox /></div>
          <div className="kpi-content">
            <div className="kpi-value">{metrics.availableProperties || 0}</div>
            <div className="kpi-label">Available Properties</div>
          </div>
        </div>

        <div className="kpi-card secondary">
          <div className="kpi-icon"><FiDollarSign /></div>
          <div className="kpi-content">
            <div className="kpi-value">{metrics.conversionRate || 0}%</div>
            <div className="kpi-label">Conversion Rate</div>
          </div>
        </div>

        <div className="kpi-card tertiary">
          <div className="kpi-icon"><FiDollarSign /></div>
          <div className="kpi-content">
            <div className="kpi-value">{formatCurrency(metrics.totalCollected || 0)}</div>
            <div className="kpi-label">Total Collected</div>
          </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="analytics-tabs">
        <button 
          className={`tab-button ${activeTab === 'overview' ? 'active' : ''}`}
          onClick={() => setActiveTab('overview')}
        >
          Overview
        </button>
        <button 
          className={`tab-button ${activeTab === 'sold' ? 'active' : ''}`}
          onClick={() => setActiveTab('sold')}
        >
          Sold Properties
        </button>
        <button 
          className={`tab-button ${activeTab === 'available' ? 'active' : ''}`}
          onClick={() => setActiveTab('available')}
        >
          Available Properties
        </button>
        <button 
          className={`tab-button ${activeTab === 'reserved' ? 'active' : ''}`}
          onClick={() => setActiveTab('reserved')}
        >
          Reserved Properties
        </button>
      </div>

      {/* Overview Tab */}
      {activeTab === 'overview' && (
        <div className="tab-content">
          <div className="charts-grid">
            <div className="chart-card">
              <h3>Property Status Distribution</h3>
              <div className="chart-wrapper">
                <Pie data={statusData} options={chartOptions} />
              </div>
              <div className="status-legend">
                <div className="legend-item sold">
                  <span className="dot"></span>
                  <span>Sold: {metrics.soldProperties}</span>
                </div>
                <div className="legend-item reserved">
                  <span className="dot"></span>
                  <span>Reserved: {metrics.reservedProperties}</span>
                </div>
                <div className="legend-item available">
                  <span className="dot"></span>
                  <span>Available: {metrics.availableProperties}</span>
                </div>
              </div>
            </div>

            <div className="chart-card">
              <h3>Property Value Distribution</h3>
              <div className="chart-wrapper">
                <Doughnut data={valueData} options={chartOptions} />
              </div>
              <div className="value-stats">
                <div className="value-item">
                  <span className="label">Sold Value:</span>
                  <span className="value">{formatCurrency(metrics.soldValue || 0)}</span>
                </div>
                <div className="value-item">
                  <span className="label">Remaining Value:</span>
                  <span className="value">{formatCurrency(metrics.remainingValue || 0)}</span>
                </div>
                <div className="value-item total">
                  <span className="label">Total Value:</span>
                  <span className="value">{formatCurrency(metrics.totalPropertyValue || 0)}</span>
                </div>
              </div>
            </div>
          </div>

          {/* Properties by Type Chart */}
          <div className="chart-card full-width">
            <h3>Properties by Type (Total vs Sold)</h3>
            <div className="chart-wrapper" style={{ height: '350px' }}>
              <Bar data={typeData} options={{
                ...chartOptions,
                scales: {
                  y: { beginAtZero: true }
                }
              }} />
            </div>
          </div>

          {/* Sales by Month */}
          <div className="chart-card full-width">
            <h3>Sales Trend (By Month)</h3>
            <div className="chart-wrapper" style={{ height: '300px' }}>
              <Bar data={salesData} options={{
                ...chartOptions,
                scales: {
                  y: { beginAtZero: true }
                }
              }} />
            </div>
          </div>
        </div>
      )}

      {/* Sold Properties Tab */}
      {activeTab === 'sold' && (
        <div className="tab-content">
          <div className="properties-grid">
            {soldProperties.length === 0 ? (
              <div className="empty-state">
                <p>No sold properties yet</p>
              </div>
            ) : (
              soldProperties.map(property => (
                <div key={property._id} className="property-card sold">
                  <div className="property-header">
                    <h4>{property.title}</h4>
                    <span className="badge-sold">Sold</span>
                  </div>
                  
                  <div className="property-info">
                    <div className="info-item">
                      <span className="label"><FiMapPin /> Location:</span>
                      <span className="value">{property.location?.city}, {property.location?.state}</span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiDollarSign /> Price:</span>
                      <span className="value price">{formatCurrency(property.price)}</span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiDollarSign /> Total Collected:</span>
                      <span className="value collected">{formatCurrency(property.totalPaid)}</span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiUser /> Customer:</span>
                      <span className="value">{property.owner?.name}</span>
                    </div>
                    <div className="info-item">
                      <span className="label">Email:</span>
                      <span className="value email">{property.owner?.email}</span>
                    </div>
                  </div>

                  <div className="payment-progress">
                    <div className="progress-header">
                      <span>Payment Progress</span>
                      <span className="percentage">{property.paymentStatus}</span>
                    </div>
                    <div className="progress-bar">
                      <div className="progress-fill" style={{
                        width: `${Math.min(100, (property.totalPaid / property.price) * 100)}%`
                      }}></div>
                    </div>
                    <div className="progress-detail">
                      {formatCurrency(property.totalPaid)} of {formatCurrency(property.price)}
                    </div>
                  </div>

                  <div className="property-features">
                    {property.features?.bedrooms > 0 && (
                      <span className="feature">­¤øÅ’ĖÅ {property.features.bedrooms} Beds</span>
                    )}
                    {property.features?.bathrooms > 0 && (
                      <span className="feature">­¤Ü┐ {property.features.bathrooms} Baths</span>
                    )}
                    {property.features?.area > 0 && (
                      <span className="feature">­¤ōÉ {property.features.area} sqft</span>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* Available Properties Tab */}
      {activeTab === 'available' && (
        <div className="tab-content">
          <div className="properties-grid">
            {availableProperties.length === 0 ? (
              <div className="empty-state">
                <p>No available properties</p>
              </div>
            ) : (
              availableProperties.map(property => (
                <div key={property._id} className="property-card available">
                  <div className="property-header">
                    <h4>{property.title}</h4>
                    <span className="badge-available">Available</span>
                  </div>
                  
                  <div className="property-info">
                    <div className="info-item">
                      <span className="label"><FiMapPin /> Location:</span>
                      <span className="value">{property.location?.city}, {property.location?.state}</span>
                    </div>
                    <div className="info-item">
                      <span className="label">Type:</span>
                      <span className="value" style={{ color: getPropertyTypeColor(property.type) }}>
                        {property.type.charAt(0).toUpperCase() + property.type.slice(1)}
                      </span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiDollarSign /> Price:</span>
                      <span className="value price">{formatCurrency(property.price)}</span>
                    </div>
                  </div>

                  <div className="property-features">
                    {property.features?.bedrooms > 0 && (
                      <span className="feature">­¤øÅ’ĖÅ {property.features.bedrooms} Beds</span>
                    )}
                    {property.features?.bathrooms > 0 && (
                      <span className="feature">­¤Ü┐ {property.features.bathrooms} Baths</span>
                    )}
                    {property.features?.area > 0 && (
                      <span className="feature">­¤ōÉ {property.features.area} sqft</span>
                    )}
                    {property.features?.parking && (
                      <span className="feature">­¤ģ┐’ĖÅ Parking</span>
                    )}
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* Reserved Properties Tab */}
      {activeTab === 'reserved' && (
        <div className="tab-content">
          <div className="properties-grid">
            {reservedProperties.length === 0 ? (
              <div className="empty-state">
                <p>No reserved properties</p>
              </div>
            ) : (
              reservedProperties.map(property => (
                <div key={property._id} className="property-card reserved">
                  <div className="property-header">
                    <h4>{property.title}</h4>
                    <span className="badge-reserved">Reserved</span>
                  </div>
                  
                  <div className="property-info">
                    <div className="info-item">
                      <span className="label"><FiMapPin /> Location:</span>
                      <span className="value">{property.location?.city}, {property.location?.state}</span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiDollarSign /> Price:</span>
                      <span className="value price">{formatCurrency(property.price)}</span>
                    </div>
                    <div className="info-item">
                      <span className="label"><FiUser /> Reserved By:</span>
                      <span className="value">{property.owner?.name}</span>
                    </div>
                    <div className="info-item">
                      <span className="label">Email:</span>
                      <span className="value email">{property.owner?.email}</span>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminAnalytics;
